def decode_rle(s):
    result = []
    i = 0
    while i < len(s):
        num_str = ""
        # Extract digits for the repeat count
        while i < len(s) and s[i].isdigit():
            num_str += s[i]
            i += 1

        # Validate that we found at least one digit
        if not num_str:
            raise ValueError("Invalid format: expected number")

        # Check for opening bracket after the number
        if i >= len(s) or s[i] != '[':
            raise ValueError("Invalid format: expected '[' after number")

        start = i + 1
        i += 1  # Move past the '['

        # Find closing bracket
        end = s.find(']', start)
        if end == -1:
            raise ValueError("Invalid format: missing closing ']'")

        chars = s[start:end]
        result.append(chars * int(num_str))
        i = end + 1  # Move past the ']'

    return ''.join(result)

