def kth_largest(nums, k):
    # Validate inputs
    if not nums:
        raise ValueError("nums must be non-empty")

    n = len(nums)
    if not (1 <= k <= n):
        raise ValueError(f"k must satisfy 1 ≤ k ≤ {n}, got k={k}")

    # Using heapq.nlargest for efficiency on large lists
    return heapq.nlargest(k, nums)[-1]
